import{_ as a,a as t,b as n,c as i}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as o,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Menambahkan Google Drive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/google-drive.md","filePath":"id-ID/upload/google-drive.md","lastUpdated":1781962217000}'),r={name:"id-ID/upload/google-drive.md"};function p(c,e,h,u,g,k){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="menambahkan-google-drive-channel" tabindex="-1">Menambahkan Google Drive Channel <a class="header-anchor" href="#menambahkan-google-drive-channel" aria-label="Permalink to &quot;Menambahkan Google Drive Channel&quot;">​</a></h1><h2 id="yang-perlu-disiapkan-dahulu" tabindex="-1">Yang Perlu Disiapkan Dahulu <a class="header-anchor" href="#yang-perlu-disiapkan-dahulu" aria-label="Permalink to &quot;Yang Perlu Disiapkan Dahulu&quot;">​</a></h2><p>Sebelum mulai, siapkan item berikut:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Dibutuhkan</th></tr></thead><tbody><tr><td>Google account</td><td>Digunakan untuk mengakses Google Cloud dan authorize Google Drive</td></tr><tr><td>Google Cloud project</td><td>Digunakan untuk enable Drive API dan membuat OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>Digunakan ImgBed untuk mendapatkan <code>Client ID</code>, <code>Client Secret</code>, dan <code>Refresh Token</code></td></tr><tr><td>ImgBed domain Anda</td><td>Digunakan untuk OAuth redirect URI. Harus cocok dengan domain yang benar-benar Anda pakai.</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="step-1-enable-google-drive-api" tabindex="-1">Step 1: Enable Google Drive API <a class="header-anchor" href="#step-1-enable-google-drive-api" aria-label="Permalink to &quot;Step 1: Enable Google Drive API&quot;">​</a></h3><ol><li>Buka Google Cloud Console.</li><li>Buat project baru atau pilih project yang sudah ada.</li><li>Masuk ke <code>APIs &amp; Services</code>.</li><li>Klik <code>Enable APIs and Services</code>.</li><li>Cari <code>Google Drive API</code>.</li><li>Buka dan klik enable.</li></ol><h3 id="step-2-configure-oauth-consent-screen" tabindex="-1">Step 2: Configure OAuth Consent Screen <a class="header-anchor" href="#step-2-configure-oauth-consent-screen" aria-label="Permalink to &quot;Step 2: Configure OAuth Consent Screen&quot;">​</a></h3><ol><li>Di Google Cloud, buka <code>Google Auth Platform</code>.</li><li>Lengkapi informasi dasar <code>Branding</code>, seperti app name, support email, dan developer contact email.</li><li>Buka <code>Audience</code>.</li><li>Untuk kebanyakan self-hosted personal deployments, pilih <code>External</code>.</li><li>Jika memilih <code>External</code>, tambahkan Google account yang ingin diauthorize di <code>Test users</code>.</li><li>Buka <code>Data Access</code>.</li><li>Tambahkan Google Drive permissions yang diperlukan.</li></ol><h3 id="step-3-buat-oauth-2-0-client" tabindex="-1">Step 3: Buat OAuth 2.0 Client <a class="header-anchor" href="#step-3-buat-oauth-2-0-client" aria-label="Permalink to &quot;Step 3: Buat OAuth 2.0 Client&quot;">​</a></h3><ol><li>Di <code>Google Auth Platform</code>, buka <code>Clients</code>.</li><li>Buat client baru.</li><li>Set application type ke <code>Web application</code>.</li><li>Beri nama client yang mudah dikenali.</li><li>Untuk authorized JavaScript origins, masukkan ImgBed URL, misalnya:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Untuk authorized redirect URIs, masukkan:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+t+'" alt="Enter domain and callback URL" loading="lazy"></p><p>Setelah client dibuat, copy nilai ini:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-isi-google-drive-channel" tabindex="-1">Step 4: Isi Google Drive Channel <a class="header-anchor" href="#step-4-isi-google-drive-channel" aria-label="Permalink to &quot;Step 4: Isi Google Drive Channel&quot;">​</a></h2><p>Di Upload Settings, pilih <code>Google Drive</code> dan isi:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Yang Diisi</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama yang mudah dikenali, misalnya <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID dari Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret dari Google Cloud</td></tr><tr><td>Refresh Token</td><td>Biarkan kosong dulu. Ambil di step berikutnya.</td></tr><tr><td>Root directory</td><td>Optional. Default adalah <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-dapatkan-refresh-token" tabindex="-1">Step 5: Dapatkan Refresh Token <a class="header-anchor" href="#step-5-dapatkan-refresh-token" aria-label="Permalink to &quot;Step 5: Dapatkan Refresh Token&quot;">​</a></h2><ol><li>Klik <code>Get Token</code>.</li><li>Pilih Google account yang ingin dihubungkan.</li><li>Selesaikan authorization prompts.</li><li>Callback page akan menampilkan <code>Refresh Token</code>.</li><li>Copy token tersebut.</li><li>Kembali ke ImgBed dan paste ke field <code>Refresh Token</code>.</li></ol><p><img src="'+i+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>Jika nanti mengganti Google account, mengganti OAuth client, atau authorization lama expired, Anda tidak perlu menghapus channel. Buka edit page dan klik <code>Reauthorize</code>.</p><h2 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h2><p>Setelah semua field terisi, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka Google Cloud</span></span>
<span class="line"><span>-&gt; Buat atau pilih project</span></span>
<span class="line"><span>-&gt; Enable Google Drive API</span></span>
<span class="line"><span>-&gt; Configure Google Auth Platform</span></span>
<span class="line"><span>-&gt; Jika Audience External, tambahkan Google account Anda ke Test users</span></span>
<span class="line"><span>-&gt; Buat Web application OAuth client</span></span>
<span class="line"><span>-&gt; Gunakan https://your-domain.com/api/oauth/google/callback sebagai redirect URI</span></span>
<span class="line"><span>-&gt; Isi Client ID dan Client Secret ke ImgBed</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Sign in dengan Google dan authorize</span></span>
<span class="line"><span>-&gt; Copy Refresh Token dari callback page</span></span>
<span class="line"><span>-&gt; Paste kembali ke ImgBed dan save</span></span>
<span class="line"><span>-&gt; Upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const f=o(r,[["render",p]]);export{v as __pageData,f as default};
